import { motion, AnimatePresence } from "framer-motion";
import { ChevronDown } from "lucide-react";
import { linkHomeDesign as design } from "../../../design/linkHomeDesign";

const LinkAdd = ({
  name,
  setName,
  isActive,
  setIsActive,
  statusOptions,
  statusDropdown,
  setStatusDropdown,
  statusRef,
  handleSubmit,
  setView,
    nameError,

}) => {
  return (
    <div className={design.pageWrapper}>
      <div className={design.container}>
        <AnimatePresence mode="wait">
          <motion.form
            key="add"
            initial={{ opacity: 0, x: 30 }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: -30 }}
            transition={{ duration: 0.3 }}
            onSubmit={handleSubmit}
            className={design.form}
          >
            <input
              type="text"
              placeholder="Link Name"
              value={name}
              onChange={(e) =>
                setName(e.target.value)
              }
              className={design.input}
              required
            />
            {nameError && (
  <p className="text-red-500 text-sm mt-2">
    {nameError}
  </p>
)}

            <div
              className={design.dropdownWrapper}
              ref={statusRef}
            >
              <button
                type="button"
                onClick={() =>
                  setStatusDropdown(!statusDropdown)
                }
                className={design.dropdownButton}
              >
                {
                  statusOptions.find(
                    (o) => o.value === isActive
                  )?.label
                }
                <ChevronDown size={16} />
              </button>

              <AnimatePresence>
                {statusDropdown && (
                  <motion.div
                    initial={{ opacity: 0, y: -6 }}
                    animate={{ opacity: 1, y: 0 }}
                    exit={{ opacity: 0 }}
                    className={design.dropdownMenu}
                  >
                    {statusOptions.map((option) => (
                      <div
                        key={option.label}
                        onClick={() => {
                          setIsActive(option.value);
                          setStatusDropdown(false);
                        }}
                        className={`${design.dropdownItem} ${
                          isActive === option.value
                            ? design.dropdownActive
                            : ""
                        }`}
                      >
                        {option.label}
                      </div>
                    ))}
                  </motion.div>
                )}
              </AnimatePresence>
            </div>

            <div className={design.buttonGroup}>
              <button
                type="submit"
                className={design.submitButton}
              >
                Create
              </button>

              <button
                type="button"
                onClick={() => setView("home")}
                className={design.cancelButton}
              >
                Cancel
              </button>
            </div>
          </motion.form>
        </AnimatePresence>
      </div>
    </div>
  );
};

export default LinkAdd;
